// HasPromoter applies the HasEdge predicate on the "promoter" edge.
func HasPromoter() predicate.ReferralCommission {
	return predicate.ReferralCommission(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, PromoterTable, PromoterColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasPromoterWith applies the HasEdge predicate on the "promoter" edge with a given conditions (other predicates).
func HasPromoterWith(preds ...predicate.User) predicate.ReferralCommission {
	return predicate.ReferralCommission(func(s *sql.Selector) {
		step := newPromoterStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

